                      <div>
                        <div><strong>Формула {block.number}</strong></div>
                        <div style={{
                          fontSize: '14px',
                          fontFamily: 'Times New Roman, serif',
                          padding: '10px',
                          backgroundColor: '#fff9f0',
                          borderRadius: '8px',
                          marginTop: '8px'
                        }}>
                          {block.formulaString || block.content}
                        </div>
                      </div>
